const animeQuestions = [
  {t:"m",q:"¿Cuál es el nombre completo de Goku en Dragon Ball?",o:["Kakarotto","Vegeta","Bardock","Raditz"],a:0,exp:"Goku es el nombre terrestre de Kakarotto, un guerrero Saiyan enviado a la Tierra.",extra:"El nombre Kakarotto proviene de 'zanahoria' (carrot), siguiendo la tradición de nombres de verduras en los Saiyans."},
  {t:"m",q:"¿Qué técnica icónica utiliza Goku con las dos manos juntas en Dragon Ball?",o:["Kamehameha","Galick Gun","Final Flash","Big Bang Attack"],a:0,exp:"El Kamehameha es la técnica especial de la familia Son y fue inventada por el Maestro Roshi.",extra:"La palabra 'Kamehameha' proviene del nombre de un rey hawaiano unificador."},
  {t:"m",q:"¿Cuántas Esferas del Dragón existen en Dragon Ball?",o:["7","5","4","9"],a:0,exp:"Son exactamente 7 Esferas del Dragón necesarias para invocar al dragón Shenlong.",extra:"En el universo de Dragon Ball existen múltiples conjuntos, como las Esferas de Namek y las Esferas Negras."},
  {t:"m",q:"¿Quién es el padre biológico de Goku en Dragon Ball?",o:["Bardock","Raditz","Nappa","King Kai"],a:0,exp:"Bardock es el padre de Goku (Kakarotto) y Raditz, un guerrero Saiyan de clase baja.",extra:"La historia de Bardock fue contada en una película especial de TV en 1990."},
  {t:"m",q:"¿Cuál es la primera transformación Super Saiyan que alcanza Goku?",o:["Super Saiyan 1","Super Saiyan 2","Super Saiyan 3","Super Saiyan Blue"],a:0,exp:"Goku alcanzó por primera vez el Super Saiyan durante su batalla contra Freezer en el planeta Namek.",extra:"Esta transformación causó sensación mundial y se considera uno de los momentos más icónicos del anime."},
  {t:"m",q:"¿Quién es el príncipe de los Saiyans en Dragon Ball Z?",o:["Vegeta","Goku","Nappa","Turles"],a:0,exp:"Vegeta es el príncipe de la raza Saiyan y uno de los personajes más populares de la serie.",extra:"A pesar de ser príncipe, Vegeta sirvió a Freezer durante años antes de rebelarse."},
  {t:"m",q:"¿Cómo se llama la técnica de fusión de Goku y Vegeta con aretes en Dragon Ball?",o:["Potara","Danza de Fusión","Metamor","Kibito"],a:0,exp:"Los aretes Potara permiten una fusión permanente (o durante una hora fuera del Mundo del Kai).",extra:"La fusión con Potara crea a Vegito, mientras que la danza de fusión crea a Gogeta."},
  {t:"m",q:"¿Cuál es el nombre del dragón que se invoca con las Esferas en Dragon Ball?",o:["Shenlong","Porunga","Zalama","Super Shenlong"],a:0,exp:"Shenlong es el dragón eterno de la Tierra que concede deseos al reunir las 7 esferas.",extra:"Porunga es el equivalente de Namek, que puede conceder tres deseos en lugar de uno."},
  {t:"m",q:"¿En qué saga de Dragon Ball Z muere Freezer por primera vez?",o:["Saga de Namek","Saga de los Androides","Saga de Cell","Saga de Majin Buu"],a:0,exp:"Freezer es derrotado por Goku en el planeta Namek durante la icónica batalla que dura varios episodios.",extra:"La batalla en Namek fue tan larga que se convirtió en un meme popular sobre el anime."},
  {t:"m",q:"¿Quién mató a Krillin en Dragon Ball Z desencadenando la ira de Goku?",o:["Freezer","Cell","Piccolo","Vegeta"],a:0,exp:"Freezer mató a Krillin lanzándolo al aire y explotándolo, lo que provocó que Goku se transformara en Super Saiyan.",extra:"Este fue uno de los momentos más emotivos de la saga, marcando la primera aparición del Super Saiyan."},
  {t:"m",q:"¿Cómo se llama el hijo mayor de Goku en Dragon Ball Z?",o:["Gohan","Goten","Bardock Jr.","Vegeta Jr."],a:0,exp:"Gohan es el primer hijo de Goku y ChiChi, nombrado así en honor al abuelo adoptivo de Goku.",extra:"El nombre Gohan significa 'arroz cocido' en japonés, siguiendo el tema culinario de su familia materna."},
  {t:"m",q:"¿Qué personaje de Dragon Ball Z superó el nivel Super Saiyan 2 antes que Goku?",o:["Gohan","Vegeta","Trunks","Piccolo"],a:0,exp:"Gohan fue el primero en alcanzar el Super Saiyan 2 durante la batalla contra Cell perfecto.",extra:"Durante el torneo del Cell Games, Gohan tenía solo 11 años cuando logró esta transformación."},
  {t:"f",q:"En Dragon Ball Super, Goku alcanza la transformación Ultra Instinto.",o:["Verdadero","Falso"],a:0,exp:"Goku logra dominar parcialmente el Ultra Instinto durante el Torneo del Poder en Dragon Ball Super.",extra:"El Ultra Instinto es una técnica que incluso los dioses de la destrucción tienen dificultad para dominar."},
  {t:"m",q:"¿Cuál es el nombre del dios de la destrucción del Universo 7 en Dragon Ball Super?",o:["Beerus","Champa","Sidra","Quitela"],a:0,exp:"Beerus es el Dios de la Destrucción del Universo 7 y fue el antagonista principal en la película Battle of Gods.",extra:"Beerus está basado en el gato doméstico de uno de los productores de la película."},
  {t:"m",q:"¿Cómo se llama el ángel guía de Beerus en Dragon Ball Super?",o:["Whis","Vados","Merus","Marcarita"],a:0,exp:"Whis es el ángel asistente de Beerus y también instructor de Goku y Vegeta.",extra:"Whis puede retroceder el tiempo tres minutos, una habilidad que salva a los guerreros en momentos críticos."},
  {t:"f",q:"En Dragon Ball Z, Piccolo y Kami originalmente eran el mismo ser.",o:["Verdadero","Falso"],a:0,exp:"Piccolo y Kami fueron separados del Namekiano original cuando este decidió convertirse en el guardián de la Tierra.",extra:"Al fusionarse de nuevo, Piccolo se convierte en el Namekiano Supremo con un poder enorme."},
  {t:"m",q:"¿Quién creó el manga original de Dragon Ball?",o:["Akira Toriyama","Masashi Kishimoto","Eiichiro Oda","Yoshihiro Togashi"],a:0,exp:"Akira Toriyama creó Dragon Ball en 1984, basándose en la novela clásica china Viaje al Oeste.",extra:"Toriyama falleció en marzo de 2024, dejando un legado enorme en el mundo del manga y anime."},
  {t:"m",q:"¿Cuál es el nombre del torneo de artes marciales en Dragon Ball?",o:["Tenkaichi Budokai","Torneo del Poder","Torneo de Cell","Gran Torneo Martial"],a:0,exp:"El Tenkaichi Budokai o Torneo Mundial de las Artes Marciales es donde Goku debuta como luchador.",extra:"Este torneo es donde Goku y Krillin se presentan por primera vez bajo el Maestro Roshi."},
  {t:"m",q:"¿Cuál es el nombre del Hokage que fundó la aldea de Konoha en Naruto?",o:["Hashirama Senju","Tobirama Senju","Hiruzen Sarutobi","Minato Namikaze"],a:0,exp:"Hashirama Senju, conocido como el Primer Hokage, fundó Konoha junto con Madara Uchiha.",extra:"Hashirama poseía el Mokuton, una habilidad rara que combinaba Doton y Suiton."},
  {t:"m",q:"¿Cuál es el nombre del zorro de nueve colas sellado dentro de Naruto?",o:["Kurama","Kyuubi","Shukaku","Chomei"],a:0,exp:"Kurama es el nombre del Nueve Colas, aunque este nombre no fue revelado hasta los arcos más avanzados.",extra:"Originalmente era conocido solo como 'el Kyuubi'; su nombre Kurama fue revelado por la madre de Naruto."},
  {t:"m",q:"¿Cuál es la técnica más poderosa de Naruto Uzumaki?",o:["Rasengan","Chidori","Kage Bunshin","Tajuu Kage Bunshin"],a:0,exp:"El Rasengan es la técnica emblema de Naruto, desarrollada y mejorada por él en múltiples versiones.",extra:"El Rasengan fue originalmente inventado por el Cuarto Hokage Minato Namikaze."},
  {t:"m",q:"¿Quién es el sensei del Equipo 7 de Naruto?",o:["Kakashi Hatake","Iruka Umino","Jiraiya","Yamato"],a:0,exp:"Kakashi Hatake es el jonin asignado al Equipo 7, formado por Naruto, Sasuke y Sakura.",extra:"Kakashi es famoso por su Sharingan en el ojo izquierdo, que obtuvo de su amigo Obito Uchiha."},
  {t:"m",q:"¿Cuál es el nombre de la aldea donde vive Naruto?",o:["Konoha","Suna","Kiri","Kumo"],a:0,exp:"Konohagakure, o la Aldea Oculta de las Hojas, es el hogar de Naruto en la nación de Hi no Kuni.",extra:"El nombre 'Konoha' significa 'hoja de árbol' en japonés."},
  {t:"m",q:"¿Quién es el padre biológico de Naruto Uzumaki?",o:["Minato Namikaze","Jiraiya","Hiruzen Sarutobi","Kakashi Hatake"],a:0,exp:"Minato Namikaze, el Cuarto Hokage, es el padre de Naruto. Murió sellando al Kyuubi en su hijo.",extra:"La identidad del padre de Naruto fue mantenida en secreto durante mucho tiempo para su protección."},
  {t:"m",q:"¿Qué clan posee el Sharingan en Naruto?",o:["Uchiha","Hyuga","Senju","Uzumaki"],a:0,exp:"El Sharingan es el Kekkei Genkai exclusivo del clan Uchiha de Konoha.",extra:"Hay varias formas del Sharingan: el básico, el Mangekyou y el Rinnegan al evolucionar."},
  {t:"m",q:"¿Quién masacró al clan Uchiha en Naruto?",o:["Itachi Uchiha","Madara Uchiha","Obito Uchiha","Danzo Shimura"],a:0,exp:"Itachi Uchiha mató a casi todo el clan Uchiha en una sola noche bajo órdenes de los ancianos de Konoha.",extra:"Itachi dejó vivir a Sasuke para que algún día lo matara y se convirtiera en héroe del pueblo."},
  {t:"m",q:"¿Cuál es el nombre de la organización de ninjas criminales en Naruto?",o:["Akatsuki","Anbu","Root","Kara"],a:0,exp:"Akatsuki es una organización de ninjas renegados que buscan capturar a las bestias con cola.",extra:"El símbolo de Akatsuki, las nubes rojas sobre fondo negro, es uno de los más reconocibles del anime."},
  {t:"m",q:"¿Quién creó el manga de Naruto?",o:["Masashi Kishimoto","Akira Toriyama","Eiichiro Oda","Tite Kubo"],a:0,exp:"Masashi Kishimoto es el autor del manga Naruto, publicado desde 1999 hasta 2014.",extra:"Kishimoto ha mencionado que Naruto tardó en publicarse porque los editores rechazaron varias versiones iniciales."},
  {t:"f",q:"Sasuke Uchiha es el rival principal de Naruto en la serie.",o:["Verdadero","Falso"],a:0,exp:"Sasuke Uchiha es el rival y mejor amigo de Naruto, y su relación es el núcleo emocional de la serie.",extra:"La relación de Naruto y Sasuke está inspirada en la dinámica de Hashirama y Madara, los fundadores de Konoha."},
  {t:"m",q:"¿Cuál es la técnica emblema de Sasuke Uchiha en Naruto?",o:["Chidori","Rasengan","Amaterasu","Susanoo"],a:0,exp:"El Chidori (o Raikiri) es la técnica creada por Kakashi y enseñada a Sasuke.",extra:"El nombre Raikiri viene de una leyenda en la que Kakashi cortó un rayo con esta técnica."},
  {t:"f",q:"En Naruto Shippuden, Pain destruye completamente la aldea de Konoha.",o:["Verdadero","Falso"],a:0,exp:"Pain usa el Shinra Tensei para destruir Konoha buscando a Naruto durante el arco de Pain.",extra:"Naruto eventualmente convence a Nagato/Pain de resucitar a todos los que murieron en el ataque."},
  {t:"m",q:"¿Cuáles son los tres Sannin de Konoha en Naruto?",o:["Jiraiya, Orochimaru y Tsunade","Kakashi, Gai y Kurenai","Naruto, Sasuke y Sakura","Minato, Kushina y Obito"],a:0,exp:"Los Tres Sannin son Jiraiya, Orochimaru y Tsunade, discípulos del Tercer Hokage reconocidos por su poder excepcional.",extra:"El nombre 'Sannin' fue dado por Hanzo de la Salamandra después de que sobrevivieran una batalla imposible."},
  {t:"m",q:"¿Quién es la madre de Naruto Uzumaki?",o:["Kushina Uzumaki","Tsunade","Rin Nohara","Mito Uzumaki"],a:0,exp:"Kushina Uzumaki es la madre de Naruto, una kunoichi del Clan Uzumaki de Whirlpool.",extra:"Kushina murió la noche del nacimiento de Naruto al extraerle el Kyuubi para sellarlo en su hijo."},
  {t:"m",q:"¿Cuál es el nombre del capitán pirata protagonista de One Piece?",o:["Monkey D. Luffy","Portgas D. Ace","Sabo","Gol D. Roger"],a:0,exp:"Monkey D. Luffy es el protagonista de One Piece, cuyo sueño es convertirse en el Rey de los Piratas.",extra:"El nombre completo revela su herencia, siendo hijo de Monkey D. Dragon y nieto de Monkey D. Garp."},
  {t:"m",q:"¿Qué Fruta del Diablo comió Luffy en One Piece?",o:["Gomu Gomu no Mi","Mera Mera no Mi","Yami Yami no Mi","Hito Hito no Mi"],a:0,exp:"Luffy comió la Gomu Gomu no Mi, que convierte su cuerpo en goma elástica.",extra:"Más tarde se reveló que la Gomu Gomu no Mi es en realidad la Hito Hito no Mi Modelo: Nika."},
  {t:"m",q:"¿Quién es el espadachín de la tripulación de Luffy en One Piece?",o:["Roronoa Zoro","Sanji","Usopp","Franky"],a:0,exp:"Roronoa Zoro es el espadachín de los Piratas del Sombrero de Paja y aspira a ser el mejor espadachín del mundo.",extra:"Zoro usa el estilo de tres espadas (Santoryu), sosteniendo una espada en la boca."},
  {t:"m",q:"¿Quién es el creador del manga One Piece?",o:["Eiichiro Oda","Akira Toriyama","Masashi Kishimoto","Tite Kubo"],a:0,exp:"Eiichiro Oda comenzó One Piece en 1997 y sigue siendo uno de los mangas más vendidos de la historia.",extra:"Oda ha dicho que planificó el final de One Piece desde el principio y se acerca gradualmente a él."},
  {t:"m",q:"¿Cuál es el nombre del barco principal de los Piratas del Sombrero de Paja?",o:["Thousand Sunny","Going Merry","Polar Tang","Moby Dick"],a:0,exp:"El Thousand Sunny fue construido por Franky después de que el Going Merry quedara destruido.",extra:"El Going Merry tuvo un funeral emotivo en el arco de Enies Lobby, uno de los momentos más tristes del anime."},
  {t:"f",q:"Shanks es uno de los Cuatro Emperadores en One Piece.",o:["Verdadero","Falso"],a:0,exp:"Shanks el Pelirrojo es uno de los Yonko o Cuatro Emperadores, los piratas más poderosos del Nuevo Mundo.",extra:"Shanks inspiró a Luffy a convertirse en pirata y le regaló su sombrero de paja."},
  {t:"m",q:"¿Qué persona de One Piece es conocida como 'El Hombre de la Llama'?",o:["Portgas D. Ace","Sabo","Marco","Thatch"],a:0,exp:"Portgas D. Ace comió la Mera Mera no Mi (Fruta del Fuego) y es el hermano adoptivo mayor de Luffy.",extra:"Ace era el capitán del Escuadrón Spade y luego el Segundo al Mando de los Piratas Barba Blanca."},
  {t:"m",q:"¿Cuántos tipos de Haki existen en One Piece?",o:["3","2","4","5"],a:0,exp:"Hay tres tipos de Haki: Busoshoku (Armamento), Kenbunshoku (Observación) y Haoshoku (Rey de los Conquistadores).",extra:"El Haoshoku Haki es extremadamente raro; solo uno en varios millones puede desarrollarlo."},
  {t:"m",q:"¿Cuál es el nombre del lugar donde se realizan las ejecuciones en One Piece?",o:["Marineford","Enies Lobby","Impel Down","Mary Geoise"],a:0,exp:"Marineford es el cuartel general de la Marina donde se llevan a cabo ejecuciones de alta importancia.",extra:"La guerra de Marineford, donde Luffy intenta salvar a Ace, es uno de los arcos más épicos de One Piece."},
  {t:"m",q:"¿Qué nación gobierna la Marina en One Piece?",o:["El Gobierno Mundial","Los Cuatro Emperadores","La Alianza Revolucionaria","La Liga Pirata"],a:0,exp:"La Marina es el brazo militar del Gobierno Mundial, la organización que controla la mayoría del mundo en One Piece.",extra:"El Gobierno Mundial oculta oscuros secretos relacionados con el Siglo Vacío que Roger descifró."},
  {t:"m",q:"¿Cómo se llaman los gigantescos humanoides que amenazan a la humanidad en Attack on Titan?",o:["Titanes","Gigantes","Colosales","Anormales"],a:0,exp:"Los Titanes son seres gigantescos que devoran humanos y son la principal amenaza en el universo de AoT.",extra:"Más adelante se revela que los Titanes son en realidad humanos transformados mediante el poder del Sujeto Ymir."},
  {t:"m",q:"¿Quién es el protagonista de Attack on Titan?",o:["Eren Yeager","Armin Arlert","Mikasa Ackerman","Levi Ackerman"],a:0,exp:"Eren Yeager es el protagonista que juró exterminar a todos los titanes tras ver a su madre ser devorada.",extra:"La evolución de Eren de héroe a antihéroe es considerada uno de los arcos de personaje más complejos del anime."},
  {t:"m",q:"¿Cuál es el nombre del Titán Colosal que destruyó la pared de Shiganshina?",o:["Bertholdt Hoover","Reiner Braun","Zeke Yeager","Falco Grice"],a:0,exp:"Bertholdt era el poseedor del Titán Colosal que inició los eventos de la serie al destruir la pared Maria.",extra:"La revelación de la identidad del Titán Colosal fue uno de los giros argumentales más impactantes del anime."},
  {t:"f",q:"En Attack on Titan, Levi Ackerman es el soldado más poderoso de la humanidad.",o:["Verdadero","Falso"],a:0,exp:"Levi es oficialmente reconocido como 'la humanidad más fuerte' por su habilidad de combate superior.",extra:"Levi es sobrino de Kenny Ackerman, un asesino legendario, y comparte el poder especial de los Ackerman."},
  {t:"m",q:"¿Cuántas Paredes protegen a la humanidad al inicio de Attack on Titan?",o:["3","2","4","5"],a:0,exp:"Hay tres paredes concéntricas: Maria (la exterior), Rosa y Sina (la interior donde vive el rey).",extra:"Se revela más adelante que las paredes están construidas con Titanes Colosales petrificados en su interior."},
  {t:"m",q:"¿Quién creó el manga Attack on Titan?",o:["Hajime Isayama","Eiichiro Oda","Akira Toriyama","Kentaro Miura"],a:0,exp:"Hajime Isayama creó Shingeki no Kyojin en 2009, completándolo en 2021.",extra:"Isayama dijo que el final fue planeado desde el principio y fue controversial entre los fans."},
  {t:"m",q:"¿Cuál es el nombre del Titán poseído por Eren Yeager al principio?",o:["Titán de Ataque","Titán Fundador","Titán de la Bestia","Titán Colosal"],a:0,exp:"Eren hereda el Titán de Ataque de su padre Grisha Yeager al consumirlo.",extra:"El nombre 'Shingeki no Kyojin' (el título original) hace referencia directamente al Titán de Ataque."},
  {t:"m",q:"¿Cuántos poderes tiene el Titán Fundador en Attack on Titan?",o:["Múltiples poderes sobre todos los Titanes","Solo el control mental","Solo la transformación","Solo la comunicación"],a:0,exp:"El Titán Fundador tiene poderes casi omnipotentes: puede alterar memoria, anatomía y controlar titanes.",extra:"El verdadero poder del Titán Fundador fue sellado por los votos del Rey Fritz durante generaciones."},
  {t:"m",q:"¿Cuál es el nombre completo del protagonista de Fullmetal Alchemist Brotherhood?",o:["Edward Elric","Alphonse Elric","Roy Mustang","Van Hohenheim"],a:0,exp:"Edward Elric, apodado el Alquimista de Acero, es el protagonista junto a su hermano Alphonse.",extra:"Edward tiene 15-16 años al inicio de la serie, lo que lo hace uno de los protagonistas más jóvenes del anime."},
  {t:"m",q:"¿Qué perdieron los hermanos Elric al intentar resucitar a su madre?",o:["Edward el brazo y pierna, Al el cuerpo","Edward el brazo derecho, Al la cabeza","Edward los ojos, Al el alma","Edward nada, Al todo"],a:0,exp:"Edward perdió el brazo izquierdo y la pierna derecha, mientras que Alphonse perdió todo su cuerpo.",extra:"Edward sacrificó su pierna para traer el alma de Al, y luego su brazo para adherir el alma de Al a una armadura."},
  {t:"m",q:"¿Cuál es la Primera Ley de la Alquimia en Fullmetal Alchemist?",o:["Equivalencia e intercambio","Todo tiene un precio","Nada viene de la nada","El equilibrio es la ley"],a:0,exp:"La Ley del Intercambio Equivalente establece que para obtener algo, se debe dar algo de igual valor.",extra:"Esta ley es la base filosófica de toda la alquimia en el universo de FMA y refleja conceptos reales de la alquimia histórica."},
  {t:"m",q:"¿Quién es el creador del manga Fullmetal Alchemist?",o:["Hiromu Arakawa","Ryohgo Narita","Tite Kubo","Yoshihiro Togashi"],a:0,exp:"Hiromu Arakawa es la autora de Fullmetal Alchemist, publicado entre 2001 y 2010.",extra:"Arakawa se inspiró en sus experiencias trabajando en una granja familiar en Hokkaido para crear algunos personajes."},
  {t:"m",q:"¿Cómo se llama el homúnculo antagonista principal en FMA Brotherhood?",o:["Father","Envidia","Lujuria","Soberbia"],a:0,exp:"Father es el homúnculo original que creó a todos los demás y busca convertirse en un dios.",extra:"Father está basado en el antagonista de la serie original de FMA (2003), donde era conocido como Dante."},
  {t:"m",q:"¿Qué título militar ostenta Edward Elric en Fullmetal Alchemist?",o:["Alquimista del Estado","Coronel","Teniente General","Mayor"],a:0,exp:"Edward es un Alquimista del Estado, específicamente conocido como el Alquimista de Acero.",extra:"Edward es el Alquimista del Estado más joven en pasar el examen, lo que logró a los 12 años."},
  {t:"f",q:"En Fullmetal Alchemist Brotherhood, Roy Mustang usa alquimia de fuego.",o:["Verdadero","Falso"],a:0,exp:"Roy Mustang es el Alquimista de la Llama, especializado en alquimia de fuego usando guantes especiales.",extra:"Los guantes de Mustang tienen el círculo de transmutación bordado y crean chispas al chasquear los dedos."},
  {t:"m",q:"¿Cuántos homúnculos existen en Fullmetal Alchemist Brotherhood?",o:["7","5","6","8"],a:0,exp:"Hay siete homúnculos, uno por cada pecado capital: Soberbia, Pereza, Avaricia, Envidia, Ira, Lujuria y Gula.",extra:"El número siete por los pecados capitales es una referencia directa a la alquimia religiosa medieval."},
  {t:"m",q:"¿Cuál es la Piedra más poderosa de la alquimia en Fullmetal Alchemist?",o:["Piedra Filosofal","Piedra Roja","Piedra de la Verdad","Piedra del Alma"],a:0,exp:"La Piedra Filosofal es el objeto más poderoso de la alquimia, capaz de superar la Ley del Intercambio Equivalente.",extra:"Se revela que la Piedra Filosofal está hecha de almas humanas, lo que la convierte en algo inmoral de crear."},
  {t:"m",q:"¿Quién es el autor del manga Death Note?",o:["Tsugumi Ohba","Masashi Kishimoto","Eiichiro Oda","Akira Toriyama"],a:0,exp:"Death Note fue escrito por Tsugumi Ohba e ilustrado por Takeshi Obata.",extra:"Ohba usa un pseudónimo; su identidad real se desconoce públicamente."},
  {t:"m",q:"¿Cómo se llama el shinigami que pierde su Death Note al inicio de la serie?",o:["Ryuk","Rem","Sidoh","Gelus"],a:0,exp:"Ryuk dejó caer su Death Note en el mundo humano por aburrimiento, y Light Yagami la encontró.",extra:"Ryuk come manzanas constantemente y describió el mundo humano como más interesante que el reino de los shinigamis."},
  {t:"m",q:"¿Cuál es el alias que usa Light Yagami como justiciero en Death Note?",o:["Kira","L","Near","Mello"],a:0,exp:"Light adopta el nombre 'Kira' (derivado de 'killer' en inglés) para su identidad como dios de la justicia.",extra:"El nombre Kira fue dado por los seguidores de Light en internet y luego adoptado mundialmente."},
  {t:"m",q:"¿Cuál es el primer nombre del famoso detective que investiga a Kira en Death Note?",o:["L","Near","Mello","Watari"],a:0,exp:"L es el detective más famoso del mundo y su nombre real es L Lawliet, aunque raramente se revela.",extra:"L tiene la costumbre de sentarse en cuclillas y siempre tiene un dedo en la boca cuando está pensando."},
  {t:"m",q:"¿Cuántos años tiene Light Yagami cuando encuentra el Death Note?",o:["17","15","18","16"],a:0,exp:"Light tiene 17 años y es estudiante de preparatoria cuando encuentra el Death Note.",extra:"Light es presentado como un genio que obtuvo las mejores calificaciones del país en los exámenes nacionales."},
  {t:"f",q:"En Death Note, L muere antes del final de la serie.",o:["Verdadero","Falso"],a:0,exp:"L muere en el episodio 25 después de que Rem escribe su nombre en el Death Note para proteger a Misa.",extra:"L fue uno de los personajes más queridos por los fans, y su muerte marcó un punto de inflexión en la serie."},
  {t:"m",q:"¿Cómo se llaman los sucesores de L en Death Note?",o:["Near y Mello","Roger y Watari","Gevanni y Lidner","Matt y Halle"],a:0,exp:"Near (Nate River) y Mello (Mihael Keehl) son los dos sucesores designados de L de Wammy's House.",extra:"Near y Mello representan dos mitades del genio de L: Near su lógica y Mello su intuición emocional."},
  {t:"m",q:"¿Qué habilidad especial otorgan los 'Ojos de Shinigami' en Death Note?",o:["Ver el nombre y tiempo de vida de cualquier persona","Ver el futuro","Matar sin tocar","Volverse invisible"],a:0,exp:"Los Ojos de Shinigami permiten ver el nombre y tiempo de vida de cualquier persona mirando su rostro.",extra:"El precio de obtener los Ojos de Shinigami es la mitad del tiempo de vida restante del humano."},
  {t:"m",q:"¿Quién es la segunda poseedora del Death Note, conocida como la segunda Kira?",o:["Misa Amane","Takada Kiyomi","Naomi Misora","Sayu Yagami"],a:0,exp:"Misa Amane es la segunda Kira, quien posee los Ojos de Shinigami y es fanática devota de Kira.",extra:"Misa es una famosa modelo e idol que se volvió seguidora de Kira después de que este mató al asesino de sus padres."},
  {t:"m",q:"¿Cómo se llama la figura heroica central de My Hero Academia?",o:["Izuku Midoriya","Katsuki Bakugo","Shoto Todoroki","All Might"],a:0,exp:"Izuku Midoriya, apodado Deku, es el protagonista de My Hero Academia que nació sin Quirk.",extra:"El apodo 'Deku' fue un insulto de Bakugo que Midoriya convirtió en su nombre de héroe."},
  {t:"m",q:"¿Qué es un Quirk en My Hero Academia?",o:["Un superpoder único","Un tipo de magia","Un arma especial","Una técnica marcial"],a:0,exp:"Un Quirk es el nombre que se le da a los superpoderes únicos que la mayoría de la población posee.",extra:"Aproximadamente el 80% de la población mundial tiene Quirk en el universo de MHA."},
  {t:"m",q:"¿Cómo se llama el héroe número uno al inicio de My Hero Academia?",o:["All Might","Endeavor","Hawks","Best Jeanist"],a:0,exp:"All Might es el Símbolo de la Paz y el héroe número uno, poseedor del One For All.",extra:"El verdadero nombre de All Might es Toshinori Yagi, y su forma musculosa es en realidad una transformación temporal."},
  {t:"m",q:"¿Cuál es el nombre del Quirk de Izuku Midoriya?",o:["One For All","All For One","Zero Gravity","Half-Cold Half-Hot"],a:0,exp:"One For All es un Quirk que acumula poder a lo largo de generaciones y puede ser transmitido voluntariamente.",extra:"One For All fue creado accidentalmente por el hermano del villano All For One hace siglos."},
  {t:"m",q:"¿Cuál es el nombre de la escuela de héroes en My Hero Academia?",o:["U.A. High School","Shiketsu High","Ketsubutsu Academy","Seijin High"],a:0,exp:"U.A. High School es la escuela de héroes más prestigiosa de Japón donde estudia Midoriya.",extra:"Las siglas U.A. son una referencia a 'Yuuei', que en japonés significa 'heroico'."},
  {t:"m",q:"¿Quién es el villano principal de My Hero Academia?",o:["All For One","Shigaraki Tomura","Dabi","Toga Himiko"],a:0,exp:"All For One es el villano que ha existido por siglos y puede robar Quirks de otros.",extra:"All For One fue el primer enemigo de One For All y ha estado detrás de la mayoría de las conspiraciones de la serie."},
  {t:"f",q:"En My Hero Academia, All Might nació con el Quirk One For All.",o:["Verdadero","Falso"],a:1,exp:"All Might es un usuario transferido de One For All; recibió el poder de su predecesor Nana Shimura.",extra:"All Might nació sin Quirk, lo que lo hace aún más especial ya que logró convertirse en el héroe más poderoso del mundo."},
  {t:"m",q:"¿Cuál es el Quirk de Shoto Todoroki?",o:["Half-Cold Half-Hot","Fire","Ice","Explosion"],a:0,exp:"Todoroki puede usar hielo con su lado derecho y fuego con su lado izquierdo.",extra:"Durante mucho tiempo, Todoroki se negó a usar el fuego por resentimiento hacia su padre Endeavor."},
  {t:"m",q:"¿Cuál es el poder de Shigaraki Tomura en My Hero Academia?",o:["Decay (Desintegración)","Explosion","One For All","Overhaul"],a:0,exp:"Shigaraki puede desintegrar cualquier cosa que toque con sus cinco dedos usando su Quirk Decay.",extra:"El Quirk de Shigaraki fue activado accidentalmente cuando era niño, matando a toda su familia."},
  {t:"m",q:"¿Quién es el creador del manga My Hero Academia?",o:["Kohei Horikoshi","Tite Kubo","Masashi Kishimoto","Eiichiro Oda"],a:0,exp:"Kohei Horikoshi es el autor de Boku no Hero Academia, publicado desde 2014.",extra:"Horikoshi mencionó que Stan Lee fue una de sus grandes influencias para crear un universo de superhéroes japonés."},
  {t:"m",q:"¿Cuál es el nombre del protagonista de Demon Slayer?",o:["Tanjiro Kamado","Zenitsu Agatsuma","Inosuke Hashibira","Giyu Tomioka"],a:0,exp:"Tanjiro Kamado es el protagonista que se convierte en cazador de demonios para salvar a su hermana Nezuko.",extra:"Tanjiro es conocido por su gran sentido del olfato, que le permite rastrear demonios y leer ataques enemigos."},
  {t:"m",q:"¿Por qué razón Nezuko Kamado se convierte en demonio en Demon Slayer?",o:["Muzan Kibutsuji la transformó","Fue mordida por un demonio menor","Tomó una poción","Nació siendo demonio"],a:0,exp:"Muzan Kibutsuji atacó a la familia Kamado y transformó a Nezuko en demonio al atacarla.",extra:"A diferencia de otros demonios, Nezuko nunca come humanos y conserva su humanidad gracias al amor por su hermano."},
  {t:"m",q:"¿Cómo se llama el arte respiratorio principal de Tanjiro en Demon Slayer?",o:["Respiración del Agua","Respiración del Sol","Respiración del Fuego","Respiración del Trueno"],a:0,exp:"Tanjiro aprende principalmente la Respiración del Agua de Sakonji Urokodaki, aunque luego también usa la del Sol.",extra:"La Respiración del Sol, llamada 'Hinokami Kagura', es la técnica original de la que derivan todas las demás."},
  {t:"m",q:"¿Cuál es el nombre del antagonista principal de Demon Slayer?",o:["Muzan Kibutsuji","Akaza","Doma","Kokushibo"],a:0,exp:"Muzan Kibutsuji es el demonio original, el más poderoso de todos y el objetivo final de la Corporación Cazademonios.",extra:"Muzan puede alterar su apariencia y tiene miedo a la flor Wisteria y la luz solar."},
  {t:"m",q:"¿Cuántos Pilares (Hashira) existen en la Corporación Cazademonios de Demon Slayer?",o:["9","7","12","10"],a:0,exp:"Hay 9 Pilares, cada uno maestro de una forma diferente de Respiración.",extra:"Los Pilares son los cazademonios más poderosos y cada uno porta una de las técnicas respiratorias principales."},
  {t:"m",q:"¿Quién es el creador del manga Demon Slayer: Kimetsu no Yaiba?",o:["Koyoharu Gotouge","Kohei Horikoshi","Tite Kubo","Yoshihiro Togashi"],a:0,exp:"Koyoharu Gotouge es el autor de Kimetsu no Yaiba, publicado de 2016 a 2020.",extra:"Gotouge mantiene su identidad en privado y se desconoce si es hombre o mujer."},
  {t:"f",q:"En Demon Slayer, Zenitsu solo puede usar sus técnicas cuando está dormido.",o:["Verdadero","Falso"],a:0,exp:"Zenitsu es tan miedoso que sus habilidades máximas se manifiestan cuando está inconsciente o dormido.",extra:"El miedo de Zenitsu contrasta humorísticamente con su enorme poder cuando está dormido."},
  {t:"m",q:"¿Cuál fue la película de Demon Slayer más taquillera de Japón?",o:["Mugen Train","Entertainment District","Swordsmith Village","Hashira Training"],a:0,exp:"Demon Slayer: Mugen Train (2020) se convirtió en la película más taquillera de la historia de Japón.",extra:"La película recaudó más de 400 millones de dólares a nivel mundial, superando a Spirited Away en Japón."},
  {t:"m",q:"¿Quién es el Pilar del Sonido en Demon Slayer?",o:["Tengen Uzui","Giyu Tomioka","Rengoku Kyojuro","Mitsuri Kanroji"],a:0,exp:"Tengen Uzui es el Hashira del Sonido, un extravagante ex-shinobi con tres esposas.",extra:"Tengen se define como 'un dios del festín' y siempre actúa con glamour en todo momento."},
  {t:"m",q:"¿Quién es el Hashira del Agua al inicio de Demon Slayer?",o:["Giyu Tomioka","Sabito","Makomo","Sakonji Urokodaki"],a:0,exp:"Giyu Tomioka es el Pilar del Agua que primero encuentra a Tanjiro y Nezuko y los deja ir.",extra:"Giyu tiene una expresión seria que lo hace parecer frío, pero en realidad se preocupa profundamente por los cazadores."},
  {t:"m",q:"¿Cuál es el nombre del Pilar de las Llamas en Demon Slayer?",o:["Rengoku Kyojuro","Tengen Uzui","Giyu Tomioka","Himejima Gyomei"],a:0,exp:"Rengoku Kyojuro es el Pilar de las Llamas, un hombre apasionado y noble que muere defendiendo el Tren Infinito.",extra:"La muerte de Rengoku en la película Mugen Train fue uno de los momentos más emotivos de la saga."},
  {t:"m",q:"¿Cuál es el nombre del protagonista de Bleach?",o:["Ichigo Kurosaki","Rukia Kuchiki","Uryu Ishida","Renji Abarai"],a:0,exp:"Ichigo Kurosaki es el protagonista, un adolescente que accidentalmente obtiene poderes de Shinigami.",extra:"El nombre 'Ichigo' puede significar 'uno que protege' en japonés, lo cual es un tema central de la serie."},
  {t:"m",q:"¿Cómo se llama la espada de alma de Ichigo Kurosaki en Bleach?",o:["Zangetsu","Benihime","Senbonzakura","Ryujin Jakka"],a:0,exp:"Zangetsu es el Zanpakuto de Ichigo, cuya forma significa 'cortando la luna'.",extra:"La forma Bankai de Ichigo se llama Tensa Zangetsu y comprime toda su reiatsu en un punto."},
  {t:"m",q:"¿Cuál es el nombre de la organización de Shinigami en Bleach?",o:["Gotei 13","Soul Society","Seireitei","Onmitsukido"],a:0,exp:"El Gotei 13 es la organización militar de los Shinigami compuesta por 13 divisiones o escuadras.",extra:"Cada división del Gotei 13 tiene un Capitán y un Teniente, con filosofías y especialidades distintas."},
  {t:"m",q:"¿Quién es el creador del manga Bleach?",o:["Tite Kubo","Masashi Kishimoto","Eiichiro Oda","Yoshihiro Togashi"],a:0,exp:"Tite Kubo creó Bleach, publicado en Weekly Shonen Jump desde 2001 hasta 2016.",extra:"Kubo es conocido por su estilo visual único y por crear diseños de personajes muy elaborados."},
  {t:"m",q:"¿Cuál es el nombre del antagonista principal de la primera saga de Bleach?",o:["Sosuke Aizen","Yhwach","Baraggan Louisenbairn","Gin Ichimaru"],a:0,exp:"Sosuke Aizen es el Capitán traidor que busca convertirse en el ser más poderoso trascendiendo todo.",extra:"La revelación de la traición de Aizen fue uno de los giros más impactantes de la serie."},
  {t:"f",q:"En Bleach, los Hollows son almas humanas corrompidas.",o:["Verdadero","Falso"],a:0,exp:"Los Hollows son almas humanas que no pudieron pasar al más allá y se corrompieron con el tiempo.",extra:"Los Hollows más poderosos pueden evolucionar en Adjuchas y eventualmente en Vasto Lorde."},
  {t:"m",q:"¿Cómo se llama la forma especial de los Espada en Bleach?",o:["Resurrección","Bankai","Shikai","Hollowificación"],a:0,exp:"La Resurrección es la liberación del poder completo de un Arrancar sellado en su Zanpakuto.",extra:"Solo los Espada más poderosos tienen una Segunda Resurrección, una forma aún más poderosa."},
  {t:"m",q:"¿Cuál es el Bankai de Byakuya Kuchiki en Bleach?",o:["Senbonzakura Kageyoshi","Kamishini no Yari","Daiguren Hyorinmaru","Ryujin Jakka"],a:0,exp:"El Bankai de Byakuya es Senbonzakura Kageyoshi, que desintegra su espada en millones de pétalos de sakura afilados.",extra:"Senbonzakura Kageyoshi es considerado uno de los Bankai más bellos visualmente de toda la serie."},
  {t:"m",q:"¿Cuál es el nombre del protagonista de Hunter x Hunter?",o:["Gon Freecss","Killua Zoldyck","Leorio Paradinight","Kurapika"],a:0,exp:"Gon Freecss es el protagonista que parte a convertirse en Hunter para encontrar a su padre Ging.",extra:"Gon tiene la capacidad innata extraordinaria de manipular el Nen, algo que normalmente toma años aprender."},
  {t:"m",q:"¿Qué es el Nen en Hunter x Hunter?",o:["Energía vital que puede ser manipulada","Un tipo de espada","Un título especial","Una técnica de lucha"],a:0,exp:"El Nen es la energía de vida (aura) que los Hunter aprenden a manipular para diversas habilidades.",extra:"El Nen tiene cuatro tipos básicos: Ten (concentrar), Zetsu (suprimir), Ren (amplificar) y Hatsu (proyectar)."},
  {t:"m",q:"¿De qué familia asesina proviene Killua en Hunter x Hunter?",o:["Zoldyck","Freecss","Nostrade","Troupe"],a:0,exp:"Killua pertenece a la familia Zoldyck, la familia de asesinos más poderosa y famosa del mundo.",extra:"Killua fue entrenado desde bebé para ser un asesino perfecto, incluso sometiéndolo a torturas para aumentar su resistencia."},
  {t:"m",q:"¿Cuál es el nombre de la araña de ladrones en Hunter x Hunter?",o:["Phantom Troupe","Mafia Nostrade","Chimera Ants","Dark Continent"],a:0,exp:"La Phantom Troupe (Brigada Fantasma) es un grupo de 13 ladrones de élite liderados por Chrollo Lucilfer.",extra:"Todos los miembros de la Troupe tienen una araña tatuada en alguna parte de su cuerpo."},
  {t:"m",q:"¿Quién es el creador del manga Hunter x Hunter?",o:["Yoshihiro Togashi","Tite Kubo","Eiichiro Oda","Masashi Kishimoto"],a:0,exp:"Yoshihiro Togashi creó Hunter x Hunter en 1998, también conocido por crear Yu Yu Hakusho.",extra:"Togashi es famoso por sus frecuentes hiatos debido a problemas de salud, haciendo que el manga se pause regularmente."},
  {t:"f",q:"En Hunter x Hunter, Gon usa el tipo de Nen llamado Potenciación.",o:["Verdadero","Falso"],a:0,exp:"Gon es del tipo Potenciación (Enhancement), que permite fortalecer las habilidades físicas del cuerpo.",extra:"La Potenciación es el tipo de Nen más directo y poderoso para el combate físico."},
  {t:"m",q:"¿Cuál es el tipo de Nen de Killua en Hunter x Hunter?",o:["Transmutación","Potenciación","Emisión","Conjuración"],a:0,exp:"Killua es del tipo Transmutación, que le permite cambiar las propiedades de su aura para imitar la electricidad.",extra:"La técnica Godspeed de Killua le permite moverse a velocidades extremas usando la electricidad de su Nen."},
  {t:"m",q:"¿Cuál es el personaje principal de Neon Genesis Evangelion?",o:["Shinji Ikari","Rei Ayanami","Asuka Langley","Kaworu Nagisa"],a:0,exp:"Shinji Ikari es el protagonista de 14 años que es reclutado para pilotar el Eva-01.",extra:"Shinji es conocido por ser uno de los protagonistas más complejos psicológicamente del anime."},
  {t:"m",q:"¿Cómo se llaman los mechas gigantes de Neon Genesis Evangelion?",o:["Evangelion","Gundam","Jaeger","Knightmare"],a:0,exp:"Los Evangelion (o Eva) son mechas bio-orgánicos que combaten contra los Ángeles.",extra:"Los Eva no son máquinas convencionales; tienen almas de humanos en su interior, incluyendo la madre de Shinji en el Eva-01."},
  {t:"m",q:"¿Cuál es el nombre de la organización que crea los Evangelion?",o:["NERV","SEELE","WILLE","GEHIRN"],a:0,exp:"NERV es la organización secreta dirigida por Gendo Ikari que maneja los Evangelion y el Proyecto Complementación Humana.",extra:"NERV es en realidad la evolución de GEHIRN, y ambas están controladas secretamente por SEELE."},
  {t:"m",q:"¿Quién es el director de NERV en Neon Genesis Evangelion?",o:["Gendo Ikari","Kozo Fuyutsuki","Ryoji Kaji","Misato Katsuragi"],a:0,exp:"Gendo Ikari, padre de Shinji, es el comandante en jefe de NERV y uno de los arquitectos de la Complementación Humana.",extra:"La relación distante y dolorosa entre Shinji y Gendo es uno de los temas centrales del anime."},
  {t:"f",q:"En Evangelion, el Eva-01 tiene el alma de la madre de Shinji.",o:["Verdadero","Falso"],a:0,exp:"El alma de Yui Ikari, madre de Shinji, fue sellada dentro del Eva-01 durante un experimento.",extra:"Esta es la razón por la que el Eva-01 tiene reacciones protectoras hacia Shinji que van más allá de la programación."},
  {t:"m",q:"¿Cuál es el nombre de la piloto del Eva-02 en Evangelion?",o:["Asuka Langley Soryu","Rei Ayanami","Mari Makinami","Yui Ikari"],a:0,exp:"Asuka Langley Soryu es la piloto del Eva-02, una niña prodigio alemana-japonesa con una personalidad explosiva.",extra:"Asuka tiene un coeficiente intelectual extraordinario y obtuvo su título universitario a los 14 años."},
  {t:"m",q:"¿Cuál es el nombre de la nave espacial en Cowboy Bebop?",o:["Bebop","Swordfish II","Hammerhead","Red Tail"],a:0,exp:"El Bebop es la nave principal de los cazarrecompensas, hogar del equipo de Spike, Jet, Faye, Edward y Ein.",extra:"El Bebop es una antigua nave de pesca de langostas que fue remodelada por Jet para vivir en ella."},
  {t:"m",q:"¿Quién es el protagonista principal de Cowboy Bebop?",o:["Spike Spiegel","Jet Black","Faye Valentine","Edward Wong"],a:0,exp:"Spike Spiegel es el exmafioso y cazarrecompensas protagonista con un pasado ligado a la organización criminal Red Dragon.",extra:"Spike practica el estilo de lucha Jeet Kune Do, el mismo arte marcial que Bruce Lee desarrolló."},
  {t:"m",q:"¿Cuál es la frase final icónica de Cowboy Bebop?",o:["You're gonna carry that weight","Bang","See you space cowboy","3,2,1 Let's Jam"],a:0,exp:"'You're gonna carry that weight' aparece al final del último episodio, haciendo referencia a las cargas que cada personaje lleva.",extra:"Esta frase también es una referencia a la canción de The Beatles 'Carry That Weight' del álbum Abbey Road."},
  {t:"m",q:"¿Cuál es el nombre del perro en Cowboy Bebop?",o:["Ein","Zero","Rex","Astro"],a:0,exp:"Ein es un Corgi Galés con inteligencia superior a lo normal, resultado de experimentos científicos.",extra:"El nombre Ein es el alemán para 'uno', haciendo juego con los nombres numerales que tienen varios personajes."},
  {t:"m",q:"¿Quién es la nemesis principal de Spike Spiegel en Cowboy Bebop?",o:["Vicious","Lin","Annie","Julia"],a:0,exp:"Vicious es el antagonista principal y excompañero de Spike en la organización criminal Red Dragon Syndicate.",extra:"La relación entre Spike y Vicious está marcada por la traición y Julia, la mujer que ambos amaban."},
  {t:"f",q:"La banda sonora de Cowboy Bebop fue compuesta por Yoko Kanno.",o:["Verdadero","Falso"],a:0,exp:"Yoko Kanno compuso la icónica banda sonora de Cowboy Bebop, mezclando jazz, blues, rock y música clásica.",extra:"La composición 'Tank!' que abre cada episodio es considerada una de las mejores sintonías de anime de la historia."},
  {t:"m",q:"¿En qué año está ambientado el universo de Cowboy Bebop?",o:["2071","2050","2099","2045"],a:0,exp:"Cowboy Bebop está ambientado en el año 2071, cuando la humanidad colonizó el sistema solar.",extra:"La vida en las colonias espaciales refleja una mezcla cultural ecléctica que da lugar al diverso estilo musical de la serie."},
  {t:"f",q:"Cowboy Bebop fue producido por el estudio Sunrise.",o:["Verdadero","Falso"],a:0,exp:"Cowboy Bebop fue producido por Sunrise (ahora Bandai Namco Filmworks) y dirigido por Shinichiro Watanabe.",extra:"Sunrise también produjo otros animes icónicos como Mobile Suit Gundam y Code Geass."},
  {t:"m",q:"¿Cuál es el nombre del estudio animador de películas como El Viaje de Chihiro?",o:["Studio Ghibli","Toei Animation","Gainax","Madhouse"],a:0,exp:"Studio Ghibli es el estudio de animación fundado por Hayao Miyazaki y Isao Takahata en 1985.",extra:"El nombre 'Ghibli' proviene de un avión de reconocimiento italiano utilizado en la Segunda Guerra Mundial."},
  {t:"m",q:"¿Quién dirigió El Viaje de Chihiro (Spirited Away)?",o:["Hayao Miyazaki","Isao Takahata","Yoshifumi Kondo","Hiromasa Yonebayashi"],a:0,exp:"Hayao Miyazaki dirigió El Viaje de Chihiro, que se convirtió en la película más taquillera de Japón hasta 2020.",extra:"El Viaje de Chihiro ganó el Oscar a Mejor Película de Animación en 2003, siendo la única no anglófona en lograrlo."},
  {t:"m",q:"¿Cuál es el nombre del espíritu central de Mi Vecino Totoro?",o:["Totoro","Catbus","Satsuki","Neko"],a:0,exp:"Totoro es el enorme y amigable espíritu del bosque que solo pueden ver los niños de corazón puro.",extra:"Totoro se ha convertido en la mascota oficial de Studio Ghibli y uno de los iconos culturales japoneses más reconocidos."},
  {t:"m",q:"¿En qué año se fundó Studio Ghibli?",o:["1985","1982","1990","1978"],a:0,exp:"Studio Ghibli fue fundado en 1985 por Hayao Miyazaki, Isao Takahata y el productor Toshio Suzuki.",extra:"La primera producción oficial fue Laputa: Castle in the Sky (1986)."},
  {t:"m",q:"¿Cómo se llama la película de Ghibli donde Sophie es convertida en anciana?",o:["El Castillo Ambulante","La Princesa Mononoke","Porco Rosso","Nausicaä del Valle del Viento"],a:0,exp:"El Castillo Ambulante (Howl's Moving Castle) narra la historia de Sophie, maldecida por la Bruja del Páramo.",extra:"La película está basada en la novela del mismo nombre de Diana Wynne Jones publicada en 1986."},
  {t:"f",q:"La Princesa Mononoke de Ghibli ganó el Oscar a Mejor Película de Animación.",o:["Verdadero","Falso"],a:1,exp:"La Princesa Mononoke no ganó el Oscar; fue El Viaje de Chihiro (2003) la película de Ghibli que ganó ese premio.",extra:"La Princesa Mononoke fue el filme más taquillero de Japón en 1997."},
  {t:"m",q:"¿Cuál es la película de Ghibli ambientada durante la Segunda Guerra Mundial?",o:["La Tumba de las Luciérnagas","Mi Vecino Totoro","El Cuento de la Princesa Kaguya","Solo mira el mar"],a:0,exp:"La Tumba de las Luciérnagas es una película sobre dos niños japoneses que sufren las consecuencias de la guerra.",extra:"A pesar de haber sido producida por Ghibli, es considerada una de las películas más tristes de la historia del cine."},
  {t:"m",q:"¿Quién es la bruja del mar en El Viaje de Chihiro de Ghibli?",o:["Yubaba","Lin","No-Face","Kamaji"],a:0,exp:"Yubaba es la bruja que dirige los baños y le roba el nombre a Chihiro (convirtiéndola en Sen).",extra:"Yubaba tiene una hermana gemela llamada Zeniba que tiene una personalidad completamente diferente."},
  {t:"m",q:"¿Cómo se llama la película de Ghibli sobre una niña que se reduce de tamaño?",o:["El mundo secreto de Arrietty","Kiki's Delivery Service","Ponyo","Nausicaä"],a:0,exp:"El mundo secreto de Arrietty está basado en la novela Los Borrowers, sobre pequeños seres que viven bajo los pisos.",extra:"La película fue dirigida por Hiromasa Yonebayashi y fue el debut de un nuevo director en Studio Ghibli."},
  {t:"m",q:"¿Cuál es el nombre de la isla flotante en la película Laputa: Castle in the Sky de Ghibli?",o:["Laputa","Pazu","Sheeta","Muska"],a:0,exp:"Laputa es la ciudad flotante que tanto la pirata Dola como los agentes del gobierno buscan en la película.",extra:"El nombre Laputa fue tomado del libro Los viajes de Gulliver de Jonathan Swift."},
  {t:"m",q:"¿Cuál es el nombre del protagonista de Sword Art Online?",o:["Kirito","Asuna","Agil","Klein"],a:0,exp:"Kirito (Kazuto Kirigaya) es el Black Swordsman, protagonista de SAO conocido por su habilidad dual.",extra:"El nombre Kirito viene de la primera sílaba de su apellido Kirigaya combinado con su nombre de pila."},
  {t:"m",q:"¿En qué consiste el peligro del juego Sword Art Online?",o:["Morir en el juego significa morir en la vida real","No pueden salir del juego voluntariamente","El casco NerveGear fríe el cerebro si alguien lo quita","Todas las anteriores"],a:3,exp:"Los jugadores están atrapados en SAO y si mueren en el juego o alguien les quita el NerveGear, mueren en la realidad.",extra:"El NerveGear transmite microondas al cerebro del usuario para mantenerlos inconscientes y también para matarlos."},
  {t:"m",q:"¿Cuál es el nombre de la compañera sentimental de Kirito en Sword Art Online?",o:["Asuna","Sinon","Leafa","Lisbeth"],a:0,exp:"Asuna Yuuki es la subcomandante del guild Knights of Blood y el interés amoroso de Kirito.",extra:"Asuna es apodada 'Flash' por su velocidad extraordinaria en combate."},
  {t:"m",q:"¿Cuántos pisos tiene el castillo Aincrad en Sword Art Online?",o:["100","50","200","75"],a:0,exp:"Aincrad es un castillo flotante con 100 pisos y los jugadores deben derrotar al jefe de cada piso para avanzar.",extra:"Al inicio de la serie, se revela que hay 10,000 jugadores atrapados en el juego."},
  {t:"m",q:"¿Cuál es el creador del juego SAO en la serie Sword Art Online?",o:["Akihiko Kayaba","Sugou Nobuyuki","Quinella","Rath"],a:0,exp:"Akihiko Kayaba es el creador del NerveGear y de Sword Art Online, el villano principal del primer arco.",extra:"Kayaba poseía el avatar en el juego de Heathcliff, el líder del guild Knights of Blood."},
  {t:"m",q:"¿Cuál es el nombre del protagonista de Jujutsu Kaisen?",o:["Yuji Itadori","Megumi Fushiguro","Nobara Kugisaki","Satoru Gojo"],a:0,exp:"Yuji Itadori es el protagonista que ingiere el dedo de Sukuna y se convierte en recipiente de un Maldito.",extra:"Yuji tiene una fuerza física extraordinaria incluso antes de ingerir el dedo de Sukuna."},
  {t:"m",q:"¿Quién es el Maldito más poderoso que posee el cuerpo de Yuji en Jujutsu Kaisen?",o:["Ryomen Sukuna","Mahito","Geto Suguru","Kenjaku"],a:0,exp:"Ryomen Sukuna es el 'Rey de las Maldiciones', el hechicero maldito más poderoso de la historia.",extra:"Sukuna tiene cuatro brazos y dos caras en su forma verdadera, y tiene un tatuaje especial en toda su forma."},
  {t:"m",q:"¿Cuál es el nombre del instructor de primer año en Jujutsu Kaisen?",o:["Satoru Gojo","Suguru Geto","Kento Nanami","Masamichi Yaga"],a:0,exp:"Satoru Gojo es el instructor más poderoso y el hechicero más fuerte del mundo en JJK.",extra:"Gojo tiene el Infinity, una técnica que hace imposible que cualquier ataque llegue a tocarlo."},
  {t:"f",q:"En Jujutsu Kaisen, Satoru Gojo es el hechicero más poderoso del mundo.",o:["Verdadero","Falso"],a:0,exp:"Gojo es reconocido universalmente como el hechicero más fuerte de su época por sus técnicas incomparables.",extra:"Gojo tiene tanto el Ojo de los Seis Ojos como el Infinito, dos poderes raros que raramente aparecen juntos."},
  {t:"m",q:"¿Quién es el creador del manga Jujutsu Kaisen?",o:["Gege Akutami","Kohei Horikoshi","Tite Kubo","Yoshihiro Togashi"],a:0,exp:"Gege Akutami es el autor de Jujutsu Kaisen, publicado desde 2018 en Weekly Shonen Jump.",extra:"El mangaka mantiene bajo perfil y rara vez aparece en público o da entrevistas."},
  {t:"m",q:"¿Cuál es el objetivo de la misión de Yuji Itadori en Jujutsu Kaisen?",o:["Consumir todos los dedos de Sukuna y morir junto a él","Derrotar a todos los hechiceros malditos","Convertirse en el hechicero más fuerte","Encontrar a Gojo sensei"],a:0,exp:"Yuji debe consumir todos los 20 dedos de Sukuna para que sea ejecutado y Sukuna muera con él.",extra:"Este plan fue diseñado para asegurar que Sukuna sea eliminado de manera controlada."},
  {t:"m",q:"¿Cuál es la técnica especial de los ojos de Gojo en Jujutsu Kaisen?",o:["Seis Ojos","Sharingan","Byakugan","Rinnegan"],a:0,exp:"Los Seis Ojos (Roppo no Me) son los ojos especiales del clan Gojo que permiten ver la energía maldita con claridad perfecta.",extra:"Los Seis Ojos aparecen tan raramente que en la historia reciente solo Gojo los ha tenido."},
  {t:"m",q:"¿Cuál es el nombre de la guild protagonista en Fairy Tail?",o:["Fairy Tail","Blue Pegasus","Lamia Scale","Sabertooth"],a:0,exp:"Fairy Tail es la poderosa y ruidosa guild mágica de Magnolia donde pertenecen Natsu, Lucy, Erza y Gray.",extra:"A pesar de ser conocida por causar daños colaterales masivos, Fairy Tail siempre sale victoriosa de sus misiones."},
  {t:"m",q:"¿Cuál es la magia de Natsu Dragneel en Fairy Tail?",o:["Dragon Slayer de Fuego","Dragon Slayer de Trueno","Dragon Slayer de Hielo","Dragon Slayer de Hierro"],a:0,exp:"Natsu usa la Magia Mata-Dragones de Fuego, enseñada por el dragón Igneel, para combatir.",extra:"Natsu puede consumir el fuego de otros para aumentar su poder, excepto el fuego que él mismo genera."},
  {t:"m",q:"¿Quién es el antagonista supremo de la saga final de Fairy Tail?",o:["Zeref Dragneel","Acnologia","Jellal Fernandes","Hades"],a:0,exp:"Zeref Dragneel es el mago negro más oscuro de la historia y hermano mayor de Natsu.",extra:"Zeref fue maldecido con la magia Ankhserma, que le da inmortalidad pero mata todo lo que lo rodea."},
  {t:"m",q:"¿Cuál es el nombre del protagonista de Tokyo Ghoul?",o:["Ken Kaneki","Touka Kirishima","Hideyoshi Nagachika","Shuu Tsukiyama"],a:0,exp:"Ken Kaneki es el estudiante universitario que se convierte en ghoul mitad humano después de un trasplante de órganos.",extra:"La transformación de Kaneki de tímido estudiante a feroz ghoul es uno de los arcos más dramáticos del anime."},
  {t:"m",q:"¿Qué es un Kagune en Tokyo Ghoul?",o:["El arma biológica de los ghouls","Un tipo de comida humana","Una organización anti-ghoul","Un tipo de investigador"],a:0,exp:"El Kagune es el arma biológica única de cada ghoul, formada por células RC que salen de la espalda.",extra:"Hay cuatro tipos de Kagune: Rinkaku, Bikaku, Ukaku y Koukaku, cada uno con distintas fortalezas."},
  {t:"m",q:"¿Cuál es el nombre de la película de animación japonesa ganadora del Oscar en 2003?",o:["El Viaje de Chihiro","La Princesa Mononoke","Mi Vecino Totoro","El Castillo en el Cielo"],a:0,exp:"El Viaje de Chihiro (Sen to Chihiro no Kamikakushi) ganó el Oscar a Mejor Película de Animación en 2003.",extra:"Es la única película de habla no inglesa en ganar el Oscar a Mejor Película de Animación desde que se creó la categoría."},
  {t:"m",q:"¿Cómo se llama el anime de comedia sobre un héroe que derrota a todos de un solo golpe?",o:["One Punch Man","Mob Psycho 100","Overlord","The Rising of the Shield Hero"],a:0,exp:"One Punch Man sigue a Saitama, un héroe que se aburrió porque es tan fuerte que derrota a todos con un puñetazo.",extra:"One Punch Man comenzó como un webcomic de ONE y luego fue redibujado por Yusuke Murata para su versión oficial."},
  {t:"m",q:"¿Cuál es el anime cyberpunk de 1988 dirigido por Katsuhiro Otomo?",o:["Akira","Ghost in the Shell","Metropolis","Megazone 23"],a:0,exp:"Akira (1988) es una película de anime dirigida por Katsuhiro Otomo basada en su propio manga.",extra:"Akira revolucionó la animación mundial y es considerado uno de los filmes más influyentes de la historia del cine."},
  {t:"m",q:"¿Cuál es el nombre del protagonista de Akira?",o:["Kaneda Shotaro","Tetsuo Shima","Kei","Ryu"],a:0,exp:"Kaneda Shotaro es el líder de una pandilla de motociclistas y el mejor amigo de Tetsuo.",extra:"La icónica motocicleta roja de Kaneda se ha convertido en uno de los símbolos más reconocibles del anime."},
  {t:"m",q:"¿Cuál es el nombre de la protagonista de Ghost in the Shell?",o:["Mayor Motoko Kusanagi","Batou","Togusa","Daisuke Aramaki"],a:0,exp:"El Mayor Motoko Kusanagi es la líder del Sector 9, una cyborg de élite que cuestiona la naturaleza de la identidad.",extra:"La pregunta filosófica central de Ghost in the Shell es qué significa ser humano cuando tu cuerpo es mayormente artificial."},
  {t:"m",q:"¿Cuál es el nombre del anime sobre un pistolero legendario en un mundo desierto futurista?",o:["Trigun","Outlaw Star","Space Dandy","Tiger & Bunny"],a:0,exp:"Trigun sigue a Vash el Stampede, un pistolero legendario con una prima de 60 mil millones en su cabeza.",extra:"Trigun tiene una mezcla peculiar de humor absurdo, drama serio y acción de armas que lo hacen único."},
  {t:"m",q:"¿Cuál es el anime shojo sobre la familia Sohma maldita?",o:["Fruits Basket","Cardcaptor Sakura","Ouran High School Host Club","Clannad"],a:0,exp:"Fruits Basket sigue a Tohru Honda viviendo con la familia Sohma, cuyos miembros se transforman en animales del zodíaco.",extra:"El remake de 2019 completó la historia que la primera adaptación de 2001 dejó inconclusa."},
  {t:"m",q:"¿Cuál es el nombre del anime de terror psicológico sobre una aldea maldita?",o:["Higurashi: When They Cry","Another","Elfen Lied","Corpse Party"],a:0,exp:"Higurashi: When They Cry sigue a Keiichi Maebara que descubre los oscuros secretos del festival del pueblo de Hinamizawa.",extra:"Higurashi es conocido por su estructura de múltiples arcos con realidades alternativas que revelan gradualmente la verdad."},
  {t:"m",q:"¿Cuál es el anime donde Shoya Ishida busca redimirse por haber hecho bullying?",o:["A Silent Voice","Your Lie in April","Anohana","Clannad"],a:0,exp:"A Silent Voice (Koe no Katachi) es una película de anime de 2016 del estudio Kyoto Animation.",extra:"La película aborda temas profundos de bullying, discapacidad, redención y salud mental de manera honesta."},
  {t:"f",q:"A Silent Voice fue producida por el Studio Ghibli.",o:["Verdadero","Falso"],a:1,exp:"A Silent Voice fue producida por Kyoto Animation (KyoAni), no por Studio Ghibli.",extra:"Kyoto Animation es conocido por producciones de alta calidad visual como Violet Evergarden, K-On! y Clannad."},
  {t:"m",q:"¿Cuál es el anime sobre un pianista que redescubre la música?",o:["Your Lie in April","Nana","Beck","Piano no Mori"],a:0,exp:"Your Lie in April (Shigatsu wa Kimi no Uso) sigue al pianista Kousei Arima que reencuentra su amor por la música.",extra:"La serie es conocida por su final devastadoramente triste y su hermosa animación musical."},
  {t:"m",q:"¿Cuál es el nombre de la técnica de movimiento ultra veloz de los Shinigami en Bleach?",o:["Shunpo","Sonido","Hierro","Bala"],a:0,exp:"El Shunpo (paso flash) es la técnica de movimiento ultrarrápido de los Shinigami, similar a la teletransportación.",extra:"La versión equivalente de los Arrancar se llama Sonido, y los Quincy usan Hirenkyaku."},
  {t:"m",q:"¿Cuál es el nombre de la técnica de Might Guy en Naruto que abre las 8 puertas internas?",o:["Hachimon Tonkou","Taijutsu Supremo","Kaiten","Hakke Rokujuyon Sho"],a:0,exp:"El Hachimon Tonkou (Apertura de las Ocho Puertas) permite a Guy liberar limitaciones biológicas a costa de su vida.",extra:"Al abrir la Octava Puerta (la de la Muerte), Guy logra igualar temporalmente el poder de Madara Uchiha."},
  {t:"m",q:"¿Cuál es el nombre del anime sobre un chico que se convierte en el Rey Fantasma?",o:["Yu Yu Hakusho","Hunter x Hunter","Bleach","Blue Exorcist"],a:0,exp:"Yu Yu Hakusho sigue a Yusuke Urameshi, un delincuente que muere y se convierte en Detective del Más Allá.",extra:"Yu Yu Hakusho fue creado por Yoshihiro Togashi, el mismo autor de Hunter x Hunter."},
  {t:"m",q:"¿Cuál es la técnica más poderosa de Yusuke en Yu Yu Hakusho?",o:["Rei Gun (Spirit Gun)","Rei Sho (Spirit Wave)","Rei Ken (Spirit Fist)","Rei Han (Spirit Sword)"],a:0,exp:"El Rei Gun o Spirit Gun dispara toda la energía espiritual de Yusuke en un poderoso rayo desde el dedo.",extra:"Yusuke desarrolló variantes como el Spirit Shotgun y el Spirit Wave a lo largo de la serie."},
  {t:"m",q:"¿Cuál es el nombre del anime sobre maestros arma y estudiantes que los portan?",o:["Soul Eater","Blue Exorcist","Noragami","Magi"],a:0,exp:"Soul Eater sigue a estudiantes de la Death Weapon Meister Academy donde algunos son armas humanas y otros los wielders.",extra:"Soul Eater fue creado por Atsushi Ohkubo, el mismo autor de Fire Force (Enen no Shouboutai)."},
  {t:"m",q:"¿Cuál es el nombre del personaje protagonista de Noragami?",o:["Yato","Yukine","Hiyori","Bishamon"],a:0,exp:"Yato es un dios menor sin santuario que sueña con tener millones de seguidores y cobra 5 yenes por deseo.",extra:"Yato acepta cualquier trabajo por 5 yenes para mantenerse relevante como deidad sin perder sus poderes."},
  {t:"m",q:"¿Cuál es el nombre del anime sobre un chico que hereda poderes demoníacos?",o:["Blue Exorcist","Noragami","Soul Eater","D.Gray-man"],a:0,exp:"Blue Exorcist sigue a Rin Okumura, hijo de Satán, que decide convertirse en exorcista para derrotar a su padre.",extra:"Rin oculta sus poderes usando la espada Kurikara que sella la llama azul de Satán en él."},
  {t:"m",q:"¿Cuál fue el primer largometraje dirigido por Hayao Miyazaki?",o:["Nausicaä del Valle del Viento","El Castillo en el Cielo","Mi Vecino Totoro","Kiki's Delivery Service"],a:0,exp:"Nausicaä del Valle del Viento (1984) fue el primer largometraje dirigido por Miyazaki, aunque técnicamente precedió a Ghibli.",extra:"El éxito de Nausicaä motivó la fundación oficial de Studio Ghibli en 1985 para el siguiente proyecto."},
  {t:"m",q:"¿Cuál es el nombre del anime sobre una banda de rock de chicas de secundaria?",o:["K-On!","BanG Dream!","Love Live!","Hibike! Euphonium"],a:0,exp:"K-On! sigue al club de música ligera de la escuela Sakuragaoka y su banda HTT (Ho-kago Tea Time).",extra:"K-On! fue un fenómeno cultural que popularizó el género 'moe' y las bandas de música en el anime."},
  {t:"m",q:"¿Cuál es el nombre del anime de mecha creado por Yoshiyuki Tomino?",o:["Mobile Suit Gundam","Evangelion","Macross","Code Geass"],a:0,exp:"Mobile Suit Gundam fue creado por Yoshiyuki Tomino en 1979 y fundó el género de 'Real Robot'.",extra:"Gundam introdujo el concepto de robots como armas de guerra reales con consecuencias políticas y humanas."},
  {t:"m",q:"¿Cuál es el nombre del padre de Sasuke Uchiha en Naruto?",o:["Fugaku Uchiha","Itachi Uchiha","Madara Uchiha","Shisui Uchiha"],a:0,exp:"Fugaku Uchiha fue el jefe del clan Uchiha y fue asesinado junto con casi todo el clan por Itachi.",extra:"Fugaku tenía ambiciones de golpe de estado contra Konoha, lo que provocó las acciones de Itachi."},
  {t:"m",q:"¿Qué acontecimiento en Death Note marca el final de la primera mitad de la serie?",o:["La muerte de L","La muerte de Misa","La captura de Light","La revelación de Near"],a:0,exp:"La muerte de L en el episodio 25 divide la serie en dos partes: la batalla L vs Kira y la batalla Near/Mello vs Kira.",extra:"Muchos fans consideran que la serie perdió fuerza después de la muerte de L."},
  {t:"m",q:"¿Cuántos episodios tiene la serie original de Neon Genesis Evangelion?",o:["26","24","13","36"],a:0,exp:"La serie original de NGE tiene 26 episodios, siendo los últimos dos muy diferentes en estilo y contenido.",extra:"Los episodios 25 y 26 son notoriamente introspectivos y abstractos, causando confusión entre los fans originalmente."},
  {t:"m",q:"¿Cuál es el nombre del tipo de Nen de Kurapika en Hunter x Hunter?",o:["Especialización","Emisión","Conjuración","Transmutación"],a:0,exp:"Kurapika es del tipo Especialización, el más raro y poderoso que no encaja en ninguna otra categoría.",extra:"Los ojos escarlata de Kurapika le permiten un tipo especial de Nen para vengarse del Phantom Troupe."},
  {t:"m",q:"¿Cómo se llama el arco en Hunter x Hunter donde se infiltran en un juego de computadora?",o:["Greed Island","Chimera Ant","Yorknew City","Heaven's Arena"],a:0,exp:"En el arco Greed Island, Gon y Killua juegan un videojuego de realidad virtual para encontrar a Ging.",extra:"Greed Island fue diseñado por el padre de Gon, Ging, y contiene cartas con objetos del mundo real."},
  {t:"m",q:"¿Cuál es el nombre del anime donde los personajes entran a mundos de libros?",o:["The Familiar of Zero","Inuyasha","No Game No Life","Sword Art Online"],a:2,exp:"No Game No Life sigue a los hermanos Sora y Shiro que son invocados a Disboard, un mundo donde todo se decide por juegos.",extra:"El anime está basado en el light novel de Yuu Kamiya y tiene un estilo visual muy colorido."},
  {t:"m",q:"¿Cuál es el nombre de la organización de Hunters en Hunter x Hunter?",o:["Hunter Association","Dark Continent Expedition","Phantom Troupe","Kaito's Group"],a:0,exp:"La Hunter Association es la organización que certifica a los Hunters y organiza el examen de selección.",extra:"Ging Freecss, padre de Gon, es miembro de los 12 Lores Bestia, el grupo de elite dentro de la Hunter Association."},
  {t:"m",q:"¿Cuál es el nombre de la forma de combate de Inosuke Hashibira en Demon Slayer?",o:["Respiración de la Bestia","Respiración del Agua","Respiración del Viento","Respiración del Sonido"],a:0,exp:"Inosuke usa la Respiración de la Bestia, un estilo único que él mismo desarrolló imitando a los animales del bosque.",extra:"Inosuke creció en el bosque criado por jabalíes, lo que influenció su estilo de lucha salvaje e impredecible."},
  {t:"m",q:"¿Cuál es el segundo arco de ataque en One Piece con Luffy usando Gear Second?",o:["Enies Lobby","Whole Cake Island","Dressrosa","Wano"],a:0,exp:"En Enies Lobby, Luffy debuta el Gear Second combatiendo contra los CP9 para rescatar a Robin.",extra:"El arco de Enies Lobby es considerado uno de los mejores de la serie por su carga emocional y las revelaciones de personajes."},
  {t:"m",q:"¿Cuál es el personaje apodado 'La humanidad más fuerte' en Attack on Titan?",o:["Levi Ackerman","Erwin Smith","Hange Zoë","Mikasa Ackerman"],a:0,exp:"Levi Ackerman recibe el título de 'La humanidad más fuerte' por sus extraordinarias habilidades de combate contra titanes.",extra:"Levi puede moverse con una velocidad y precisión tan excepcionales que puede derrotar titanes solo mientras que otros necesitan equipos."},
  {t:"m",q:"¿Cuál es el nombre de la técnica de ataque de Natsu en Fairy Tail?",o:["Fire Dragon's Roar","Dragon Force","Fire Dragon's Iron Fist","Fairy Sphere"],a:0,exp:"El Fire Dragon's Roar es el ataque de aliento de fuego de Natsu, su técnica más icónica.",extra:"La versión más poderosa es el Crimson Lotus: Exploding Flame Blade, usada contra enemigos de alto nivel."},
  {t:"m",q:"¿Cuántos Titanes con poderes especiales existen en Attack on Titan?",o:["9","7","5","12"],a:0,exp:"Hay nueve Titanes especiales heredados del poder original de Ymir Fritz hace mil quinientos años.",extra:"Los nueve titanes son: Colosal, Acorazado, Femenino, Bestia, Quijada, Carruaje, Martillo de Guerra, Fundador y el Titán de Ataque."},
  {t:"m",q:"¿Cuál es el nombre del anime donde un estudiante se convierte en dios de otra dimensión?",o:["The Devil is a Part-Timer","KonoSuba","Overlord","That Time I Got Reincarnated as a Slime"],a:2,exp:"Overlord sigue a Momonga/Ainz Ooal Gown, un jugador atrapado en un videojuego como su personaje de máximo nivel.",extra:"Overlord es notable por presentar al protagonista como un poderoso señor oscuro en lugar de un héroe convencional."},
  {t:"m",q:"¿Cuál es el nombre del protagonista de Sword Art Online en el arco de Gun Gale Online?",o:["Kirito sigue siendo el protagonista","Asuna toma el rol","Sinon es la protagonista","LLENN es la protagonista"],a:0,exp:"Kirito sigue siendo el protagonista en Gun Gale Online, aunque inicialmente usa un avatar femenino.",extra:"La apariencia femenina del avatar de Kirito en GGO fue resultado del algoritmo de selección del juego."},
  {t:"m",q:"¿Qué diferencia al Titan Fundador de los demás Titans en Attack on Titan?",o:["Puede controlar a todos los Titanes y alterar a los Subjects of Ymir","Solo es más grande","Solo tiene más fuerza","Puede regenerarse más rápido"],a:0,exp:"El Titán Fundador tiene poderes casi omnipotentes sobre todos los Subjects of Ymir: puede alterar su memoria, anatomía y controlar titanes.",extra:"El verdadero poder del Titán Fundador fue sellado por los votos del Rey Fritz durante generaciones."},
  {t:"m",q:"¿Cuál es el nombre del personaje conocido como el Shinigami de los Ojos en Death Note?",o:["Ryuk","Rem","Armonia Jenkins","Jealous"],a:0,exp:"Ryuk es el Shinigami que voluntariamente dejó caer su Death Note para entretenerse con los humanos.",extra:"A diferencia de Rem, que tiene sentimientos por Misa, Ryuk solo está interesado en el entretenimiento que le brinda Light."},
  {t:"m",q:"¿Cuál es el nombre del padre adoptivo de Goku en Dragon Ball?",o:["Abuelo Gohan","Maestro Roshi","Bardock","Kami"],a:0,exp:"El abuelo Gohan, un anciano humano, encontró al bebé Goku y lo crió hasta su muerte accidental.",extra:"El nombre del hijo mayor de Goku, Gohan, fue elegido en honor al abuelo adoptivo de Goku."},
  {t:"m",q:"¿Cuál es el elemento que debilita a los demonios en Demon Slayer además de la luz solar?",o:["Flores Wisteria","Agua bendita","Sal","Hierro"],a:0,exp:"Las flores Wisteria son venenosas para los demonios y se usan para crear defensas y venenos contra ellos.",extra:"Las espadas Nichirin están forjadas con un mineral especial que absorbe la luz solar para poder matar demonios."},
  {t:"m",q:"¿Cuál es el nombre del anime de deportes sobre voleibol?",o:["Haikyuu!!","Kuroko no Basket","Ace of Diamond","Free! Iwatobi Swim Club"],a:0,exp:"Haikyuu!! sigue al equipo de voleibol de la escuela secundaria Karasuno con el protagonista Shoyo Hinata.",extra:"El manga fue creado por Haruichi Furudate y es considerado uno de los mejores animes deportivos de la historia."},
  {t:"m",q:"¿Cuál es el tipo de poder del personaje Endeavor en My Hero Academia?",o:["Hellflame (Llamas del Infierno)","Ice","Explosion","Air"],a:0,exp:"Endeavor posee el Quirk Hellflame, que le permite generar y controlar poderosas llamas.",extra:"Endeavor es el padre de Shoto Todoroki y el héroe número dos (luego número uno) en el ranking de héroes."},
  {t:"m",q:"¿Cuál es el nombre completo del Rey de las Maldiciones en Jujutsu Kaisen, principal antagonista de la serie?",o:["Ryomen Sukuna","Kenjaku","Mahito","Suguru Geto"],a:0,exp:"Ryomen Sukuna es el Rey de las Maldiciones, un mago maldito de hace mil años fragmentado en 20 dedos que sirven como objetos malditos.",extra:"Itadori Yuji los va ingiriendo a lo largo de la serie, compartiendo su cuerpo con Sukuna. La técnica de dominio de Sukuna, Fuego Malicioso, puede destruir todo a su alrededor."},
  {t:"m",q:"¿Qué técnica de dominio usa Satoru Gojo que lo hace prácticamente invencible en Jujutsu Kaisen?",o:["Unlimited Void (Vacío Ilimitado)","Malevolent Shrine","Coffin of the Iron Mountain","Chimera Shadow Garden"],a:0,exp:"El Domain Expansion de Gojo se llama Unlimited Void y abruma a los enemigos con información infinita, paralizándolos.",extra:"Gojo es considerado el hechicero más fuerte de la era moderna. Su Infinito actúa como barrera pasiva que hace casi imposible tocarlo físicamente."},
  {t:"m",q:"¿Qué es Ken Kaneki al comienzo de Tokyo Ghoul?",o:["Un estudiante universitario humano que se convierte en medio-ghoul tras un ataque","Un ghoul de pura sangre que finge ser humano","Un investigador del CCG","Un ghoul sin territorio propio"],a:0,exp:"Ken Kaneki es un estudiante humano que sobrevive a un ataque de la ghoul Rize Kamishiro, convirtiéndose en el primer híbrido humano-ghoul conocido.",extra:"Su transformación lo obliga a enfrentarse tanto al mundo humano como al mundo de los ghouls, que deben alimentarse de carne humana para sobrevivir."},
  {t:"m",q:"¿Cómo se llama el sistema de energía sobrenatural que usan los personajes de Hunter x Hunter para desarrollar poderes únicos?",o:["Nen","Chakra","Reiatsu","Ki"],a:0,exp:"El Nen es la energía vital que rodea a todos los seres vivos. Aprenderlo permite a los personajes desarrollar habilidades únicas llamadas Hatsu.",extra:"El sistema Nen divide los poderes en seis categorías: Enhancement, Emission, Manipulation, Conjuration, Transmutation y Specialization, siendo uno de los sistemas de magia más elaborados del anime."},
  {t:"m",q:"¿Cuántos episodios tiene la serie original de Cowboy Bebop (1998)?",o:["26 episodios llamados sessions","36 episodios","24 episodios","13 episodios"],a:0,exp:"Cowboy Bebop consta de 26 episodios llamados 'sessions' (sesiones), en referencia al lenguaje musical que impregna toda la serie.",extra:"Fue creada por Shinichiro Watanabe para Studio Sunrise en 1998. La serie mezcla western espacial, noir y jazz, y es considerada una de las mejores series de anime jamás producidas."},
  {t:"m",q:"¿Qué significa 'shonen' en el contexto del anime y el manga japonés?",o:["Publicaciones dirigidas a chicos jóvenes, con acción y amistad como temas","Anime de romance para adultos","Anime de terror psicológico","Anime de comedia infantil"],a:0,exp:"'Shonen' (少年) significa 'chico joven' en japonés. Las publicaciones shonen están dirigidas a chicos entre 12 y 18 años con temas de amistad, superación y acción.",extra:"Las tres series shonen más populares de los 2000-2010s fueron Naruto, Bleach y One Piece, conocidas como 'The Big Three'. Dragon Ball se considera el precursor del género moderno."},
  {t:"m",q:"¿Cuál es el nombre del VRMMORPG en el que quedan atrapados los jugadores al inicio de Sword Art Online?",o:["Sword Art Online (SAO)","Alfheim Online","Gun Gale Online","Underworld"],a:0,exp:"Sword Art Online es el juego de realidad virtual que atrapa a 10.000 jugadores con los Nervegear: morir en el juego significa morir en la realidad.",extra:"La serie fue escrita por Reki Kawahara. El universo expandió el mundo con otros juegos: Alfheim Online (ALO) en el arco 2, Gun Gale Online (GGO) en el arco 3, y Underworld en el arco 4 (Alicization)."},
  {t:"m",q:"¿Quién es Osamu Tezuka y cuál es su importancia en la historia del manga y el anime?",o:["El 'Dios del Manga', creador de Astro Boy y pionero del manga moderno","El fundador del estudio Ghibli","El primer director de películas anime","El creador de Pokémon"],a:0,exp:"Osamu Tezuka (1928-1989) es el 'Dios del Manga' por haber desarrollado las convenciones visuales del manga moderno, incluyendo los ojos grandes y las narrativas cinematográficas.",extra:"Sus obras incluyen Astro Boy, Black Jack, Buddha, Kimba the White Lion y Phoenix. Fundó Mushi Production, precursor de muchos estudios modernos. Influenció a prácticamente todo el manga y anime posterior."},
  {t:"m",q:"¿Cuál es el nombre del Quirk heredado de All Might que recibe Izuku Midoriya en My Hero Academia?",o:["One For All","All For One","Full Cowl","Infinite Power"],a:0,exp:"One For All es el Quirk que acumula el poder de todos sus usuarios anteriores y puede transferirse de generación en generación. All Might lo transmite a Midoriya.",extra:"One For All es la antítesis del Quirk del villano All For One, quien puede robar y distribuir poderes. La lucha entre ambos Quirks es el eje central del conflicto en My Hero Academia."},
  {t:"m",q:"¿Cuál es el nombre del protagonista de Bleach y qué poder adquiere al inicio de la serie?",o:["Ichigo Kurosaki, que absorbe los poderes de la shinigami Rukia por accidente","Rukia Kuchiki, que le da sus poderes voluntariamente a un humano","Uryu Ishida, un Quincy cazador de shinigami","Renji Abarai, el teniente del Soul Society"],a:0,exp:"Ichigo Kurosaki es un adolescente que puede ver espíritus. Al inicio, absorbe los poderes de la shinigami Rukia Kuchiki para salvar a su familia de un Hollow.",extra:"Ichigo se convierte en Shinigami Sustituto. A lo largo de la serie descubre poderes de Hollow, Quincy y Fullbring, siendo uno de los personajes con más tipos de poderes de todo el anime."},
  {t:"m",q:"¿Qué es el Modo Sabio (Sage Mode) en Naruto y qué ventajas ofrece al usuario?",o:["Absorber la energía natural del entorno para amplificar el chakra y la percepción","Convocar a todos los animales del mundo","Volverse invisible en batalla","Revivir a personas muertas"],a:0,exp:"El Modo Sabio permite absorber la Energía Natural del entorno y combinarla con el chakra propio, amplificando enormemente la fuerza, velocidad y percepción del usuario.",extra:"Naruto aprendió el Sage Mode en Monte Myoboku con los sapos. En Modo Sabio puede sentir el chakra a distancia. Más adelante domina el Sage Mode de los Seis Caminos, considerablemente más poderoso."},
  {t:"m",q:"¿Qué gremio de magia protagoniza la serie Fairy Tail y quiénes son sus miembros más icónicos?",o:["Fairy Tail, con Natsu, Lucy, Erza, Gray y Wendy como miembros principales","Blue Pegasus, con Lyon y su equipo","Sabertooth, los rivales de Natsu","Lamia Scale, el gremio de Ur y sus discípulos"],a:0,exp:"Fairy Tail es el gremio principal de la serie, conocido por su fuerza y su espíritu de camaradería. Natsu Dragneel (Slayer de Fuego), Lucy Heartfilia, Erza Scarlet, Gray Fullbuster y Wendy Marvell son sus integrantes más conocidos.",extra:"El gremio fue fundado por Mavis Vermillion, la Primera Maestra, cuyo cuerpo duerme en Fairy Tail Island. El nombre del gremio alude al misterio de si las hadas tienen o no cola, metáfora de los sueños imposibles."},
  {t:"f",q:"Fullmetal Alchemist: Brotherhood (2009) es una adaptación más fiel al manga original que el primer anime de Fullmetal Alchemist del 2003.",o:["Verdadero","Falso"],a:0,exp:"Brotherhood sigue el manga de Hiromu Arakawa casi de principio a fin, mientras que el anime de 2003 tomó una dirección diferente al manga a mitad de su producción por alcanzarlo en publicación.",extra:"Brotherhood se considera la adaptación 'canónica'. Sin embargo, muchos fans también valoran el anime de 2003 por su atmósfera más oscura y diferente, con un final alternativo propio."}
];

export default animeQuestions;
